const webhook = $('Webhook').item.json.body;

// Garante que name e description existam no payload final
const payload = {
  ...$json,
  name: $json.name || $json.input?.name,
  description: $json.description || $json.input?.description,
  active_preset_id: webhook.active_preset_id,
  track: webhook.track,
  current_sessions: webhook.current_sessions
};

if (!payload.name || !payload.description) {
  throw new Error('O Agente deve fornecer name e description para salvar como novo preset.');
}

return await $workflow.execute('[TOOL] Worker_Supabase_Presets', payload);
